 using Store;

 namespace Store.Tests;

 [TestClass]
 public sealed class ShoppingCartTests
 {
     private ShoppingCart _sut = null!;

     [TestInitialize]
     public void Setup() => _sut = new ShoppingCart();

     // ── AddItem ────────────────────────────────────────────────

     [TestMethod]
     [DataRow("SKU-1", 1, 9.99, DisplayName = "Single item")]
     [DataRow("SKU-2", 5, 2.50, DisplayName = "Multiple quantity")]
     public void AddItem_ValidInput_AddsToCart(string sku, int qty, double price)
     {
         _sut.AddItem(sku, qty, (decimal)price);

         Assert.IsTrue(_sut.Items.ContainsKey(sku));
         Assert.AreEqual(qty, _sut.Items[sku].Quantity);
         Assert.AreEqual((decimal)price, _sut.Items[sku].Price);
     }

     [TestMethod]
     public void AddItem_SameSkuTwice_CombinesQuantityAndUpdatesPrice()
     {
         _sut.AddItem("SKU-1", 2, 10.00m);
         _sut.AddItem("SKU-1", 3, 12.00m);

         Assert.AreEqual(5, _sut.Items["SKU-1"].Quantity);
         Assert.AreEqual(12.00m, _sut.Items["SKU-1"].Price);
     }

     [TestMethod]
     public void AddItem_ZeroPriceItem_Succeeds()
     {
         _sut.AddItem("FREEBIE", 1, 0.00m);

         Assert.AreEqual(0.00m, _sut.Items["FREEBIE"].Price);
     }

     [TestMethod]
     [DataRow(null, DisplayName = "Null SKU")]
     [DataRow("", DisplayName = "Empty SKU")]
     [DataRow("   ", DisplayName = "Whitespace SKU")]
     public void AddItem_InvalidSku_Throws(string? sku)
     {
         Assert.ThrowsExactly<ArgumentException>(() => _sut.AddItem(sku!, 1, 5.00m));
     }

     [TestMethod]
     [DataRow(0, DisplayName = "Zero quantity")]
     [DataRow(-1, DisplayName = "Negative quantity")]
     public void AddItem_InvalidQuantity_Throws(int qty)
     {
         Assert.ThrowsExactly<ArgumentOutOfRangeException>(() => _sut.AddItem("SKU-1", qty, 5.00m));
     }

     [TestMethod]
     public void AddItem_NegativePrice_Throws()
     {
         Assert.ThrowsExactly<ArgumentOutOfRangeException>(() => _sut.AddItem("SKU-1", 1, -1.00m));
     }

     // ── RemoveItem ─────────────────────────────────────────────

     [TestMethod]
     public void RemoveItem_ExistingItem_RemovesFromCart()
     {
         _sut.AddItem("SKU-1", 1, 10.00m);

         _sut.RemoveItem("SKU-1");

         Assert.IsEmpty(_sut.Items);
     }

     [TestMethod]
     public void RemoveItem_NonExistentSku_ThrowsKeyNotFoundException()
     {
         Assert.ThrowsExactly<KeyNotFoundException>(() => _sut.RemoveItem("MISSING"));
     }

     [TestMethod]
     [DataRow(null, DisplayName = "Null SKU")]
     [DataRow("", DisplayName = "Empty SKU")]
     public void RemoveItem_InvalidSku_Throws(string? sku)
     {
         Assert.ThrowsExactly<ArgumentException>(() => _sut.RemoveItem(sku!));
     }

     // ── CalculateTotal ─────────────────────────────────────────

     [TestMethod]
     public void CalculateTotal_EmptyCart_ReturnsZero()
     {
         Assert.AreEqual(0m, _sut.CalculateTotal());
     }

     [TestMethod]
     public void CalculateTotal_SingleItem_ReturnsCorrectTotal()
     {
         _sut.AddItem("SKU-1", 3, 4.50m);

         Assert.AreEqual(13.50m, _sut.CalculateTotal());
     }

     [TestMethod]
     public void CalculateTotal_MultipleItems_SumsAll()
     {
         _sut.AddItem("A", 2, 10.00m); // 20.00
         _sut.AddItem("B", 1, 5.99m);  //  5.99

         Assert.AreEqual(25.99m, _sut.CalculateTotal());
     }

     [TestMethod]
     public void CalculateTotal_AfterRemovingItem_ExcludesRemoved()
     {
         _sut.AddItem("A", 1, 10.00m);
         _sut.AddItem("B", 1, 20.00m);
         _sut.RemoveItem("A");

         Assert.AreEqual(20.00m, _sut.CalculateTotal());
     }

     // ── ApplyCoupon ────────────────────────────────────────────

     [TestMethod]
     [DataRow("SAVE10", 100.00, 90.00, DisplayName = "10% off")]
     [DataRow("SAVE20", 100.00, 80.00, DisplayName = "20% off")]
     [DataRow("HALF", 100.00, 50.00, DisplayName = "50% off")]
     public void ApplyCoupon_ValidCode_DiscountsTotal(string code, double price, double expected)
     {
         _sut.AddItem("SKU-1", 1, (decimal)price);
         _sut.ApplyCoupon(code);

         Assert.AreEqual((decimal)expected, _sut.CalculateTotal());
     }

     [TestMethod]
     public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
     {
         Assert.ThrowsExactly<ArgumentException>(() => _sut.ApplyCoupon("BOGUS"));
     }

     [TestMethod]
     [DataRow(null, DisplayName = "Null code")]
     [DataRow("", DisplayName = "Empty code")]
     public void ApplyCoupon_NullOrEmpty_Throws(string? code)
     {
         Assert.ThrowsExactly<ArgumentException>(() => _sut.ApplyCoupon(code!));
     }

     [TestMethod]
     public void ApplyCoupon_ReplacePreviousCoupon_UsesLatest()
     {
         _sut.AddItem("SKU-1", 1, 100.00m);
         _sut.ApplyCoupon("SAVE10");
         _sut.ApplyCoupon("SAVE20");

         Assert.AreEqual(80.00m, _sut.CalculateTotal());
         Assert.AreEqual("SAVE20", _sut.AppliedCoupon);
     }

     [TestMethod]
     public void CalculateTotal_NoCoupon_NoDiscount()
     {
         _sut.AddItem("SKU-1", 1, 100.00m);

         Assert.AreEqual(100.00m, _sut.CalculateTotal());
         Assert.IsNull(_sut.AppliedCoupon);
     }

     // ── Rounding ───────────────────────────────────────────────

     [TestMethod]
     public void CalculateTotal_WithCoupon_RoundsToTwoDecimals()
     {
         _sut.AddItem("SKU-1", 3, 9.99m); // 29.97
         _sut.ApplyCoupon("SAVE10");       // 29.97 * 0.90 = 26.973

         Assert.AreEqual(26.97m, _sut.CalculateTotal());
     }
 }

